import { TRACK_KIND_OPTIONS } from '.';

type TrackKindOptionsProps = typeof TRACK_KIND_OPTIONS;
export type trackKindOptionProps = TrackKindOptionsProps[ number ];

/**
 * VideoPress processing state of a track's underlying file. Distinct from a
 * caption track's WordPress post status (`draft`/`publish`).
 */
export type TrackProcessingStatus = 'ready' | 'serving' | 'processing' | 'syncing' | 'failed';

/**
 * How a track was produced: `asr` for auto-generated speech recognition,
 * `manual` for an author-supplied track.
 */
export type TrackSource = 'asr' | 'manual';

export type VideoTextTrack = {
	id?: string | number;
	label: string;
	srcLang: string;
	kind: trackKindOptionProps;
	src: string;
	source?: TrackSource;
	status?: TrackProcessingStatus;
	isAutoGenerated?: boolean;
	isAutoSynced?: boolean;
	isDraft?: boolean;
	failureReason?: string;
	downloadUrl?: string;
};

export type VideoTracksListResult = {
	tracks: VideoTextTrack[];
	supportedFormats: string[];
};

export type UploadTrackDataProps = {
	label: string;
	srcLang: string;
	kind: trackKindOptionProps;
	tmpFile: File;
};

export type DeleteTrackDataProps = {
	id?: string | number;
	kind: trackKindOptionProps;
	srcLang: string;
};

export type UpdateTrackDataProps = {
	id?: string | number;
	label: string;
	srcLang: string;
	kind: trackKindOptionProps;
	src?: string;
};
